"use client";

import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import {
  Popover,
  PopoverContent,
  PopoverTrigger,
} from "@/components/ui/popover";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import {
  ChevronLeft,
  ChevronRight,
  Edit3,
  ExternalLink,
  Eye,
  Globe,
  Lock,
} from "lucide-react";
import { useCallback, useState } from "react";
import useSWR from "swr";
import useSWRMutation from "swr/mutation";
import { deployFiles, getDeploymentStatus } from "../actions/deploy-files";

type DeploymentError = {
  code: "INVALID_REQUEST" | "UNAUTHORIZED" | "DEPLOYMENT_FAILED";
  error: string;
};

type DeploymentStatus = Awaited<ReturnType<typeof getDeploymentStatus>>;

type DeploymentState =
  | { status: "idle" }
  | { status: "deploying"; progress: string }
  | { status: "polling"; deploymentId: string; url?: string; progress: string }
  | { status: "ready"; url: string }
  | { status: "error"; message: string };

type ViewState = "main" | "domain" | "visibility";
type VisibilityOption = "public" | "private";

const REFRESH_INTERVAL = 10_000;

function useDeployment() {
  const [deploymentId, setDeploymentId] = useState<string | null>(null);
  const [deploymentUrl, setDeploymentUrl] = useState<string | null>(null);
  const [error, setError] = useState<DeploymentError | null>(null);

  const { trigger: deploy, isMutating: isDeploying } = useSWRMutation(
    "/api/deploy",
    () =>
      deployFiles({
        deploymentName: `platforms-deploy-test-${Date.now()}`.toLowerCase(),
      })
  );

  const { data: currentStatus, isLoading: isPolling } =
    useSWR<DeploymentStatus>(
      deploymentId ? deploymentId : null,
      (nonNullDeploymentId) => getDeploymentStatus(nonNullDeploymentId),
      {
        refreshInterval: deploymentId ? REFRESH_INTERVAL : 0,
        revalidateOnFocus: false,
        shouldRetryOnError: true,
        errorRetryCount: 3,
        errorRetryInterval: 2000,
      }
    );

  const startDeployment = useCallback(async () => {
    setError(null);
    const result = await deploy();
    setDeploymentUrl(result.url);
    setDeploymentId(result.id);
    return result;
  }, [deploy]);

  const getDeploymentState = useCallback((): DeploymentState => {
    if (isDeploying) {
      return { status: "deploying", progress: "Starting deployment..." };
    }

    if (currentStatus?.readyState === "ERROR") {
      return {
        status: "error",
        message: "Your deployment failed.",
      };
    }

    if (deploymentId && currentStatus) {
      const progress =
        currentStatus.readyState === "BUILDING"
          ? "Building application..."
          : "Initializing deployment...";

      if (currentStatus.readyState === "READY") {
        return { status: "ready", url: currentStatus.url };
      }

      return {
        status: "polling",
        deploymentId,
        url: deploymentUrl || currentStatus.url,
        progress,
      };
    }

    if (deploymentId && isPolling) {
      return {
        status: "polling",
        deploymentId,
        url: deploymentUrl || undefined,
        progress: "Checking deployment status...",
      };
    }

    return { status: "idle" };
  }, [isDeploying, deploymentId, currentStatus, deploymentUrl, isPolling]);

  return { state: getDeploymentState(), startDeployment, deploymentUrl, error };
}

export function DeployPopover() {
  const [viewState, setViewState] = useState<ViewState>("main");
  const [customDomain, setCustomDomain] = useState<string>("");
  const [visibility, setVisibility] = useState<VisibilityOption>("public");
  const [tempVisibility, setTempVisibility] =
    useState<VisibilityOption>("public");

  const { state, startDeployment } = useDeployment();

  const handleDeploy = useCallback(async () => {
    await startDeployment();
  }, [startDeployment]);

  const handleBack = () => {
    setViewState("main");
  };

  const handleSaveVisibility = () => {
    setVisibility(tempVisibility);
    setViewState("main");
  };

  const handleCancelVisibility = () => {
    setTempVisibility(visibility);
    setViewState("main");
  };

  const handleAddDomain = () => {
    // Handle domain addition logic here
    setViewState("main");
  };

  if (viewState === "domain") {
    return (
      <Popover>
        <PopoverTrigger asChild>
          <Button variant="outline">Publish</Button>
        </PopoverTrigger>
        <PopoverContent className="w-96 p-0">
          <div className="flex items-center gap-2 border-b p-2">
            <Button
              aria-label="Back"
              className="size-8"
              onClick={handleBack}
              size="icon"
              variant="ghost"
            >
              <ChevronLeft className="h-3" />
            </Button>
            <h3 className="font-medium">Add a Custom Domain</h3>
          </div>

          <div className="space-y-4 p-4">
            <p className="text-muted-foreground text-sm">
              Assign a custom vercel.app subdomain to make your project more
              memorable.
            </p>

            <div className="relative">
              <Input
                className="w-full pr-21"
                onChange={(e) => setCustomDomain(e.target.value)}
                placeholder="your-domain"
                value={customDomain}
              />
              <span className="-translate-y-1/2 absolute top-1/2 right-3 text-muted-foreground text-sm">
                .vercel.app
              </span>
            </div>

            <Button className="w-full" onClick={handleAddDomain}>
              Add Domain
            </Button>
          </div>
        </PopoverContent>
      </Popover>
    );
  }

  if (viewState === "visibility") {
    return (
      <Popover>
        <PopoverTrigger asChild>
          <Button variant="outline">Publish</Button>
        </PopoverTrigger>
        <PopoverContent className="w-96 p-0">
          <div className="flex items-center gap-2 border-b p-2">
            <Button
              aria-label="Back"
              className="size-8"
              onClick={handleBack}
              size="icon"
              variant="ghost"
            >
              <ChevronLeft className="h-3" />
            </Button>
            <h3 className="font-medium">Visibility</h3>
          </div>

          <div className="space-y-4 p-4">
            <div className="space-y-2">
              <Label
                className="text-muted-foreground text-sm"
                htmlFor="visibility"
              >
                Visibility
              </Label>
              <Select
                onValueChange={(value: VisibilityOption) =>
                  setTempVisibility(value)
                }
                value={tempVisibility}
              >
                <SelectTrigger className="w-full" id="visibility">
                  <div className="flex items-center gap-2">
                    <SelectValue />
                  </div>
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="public">
                    <div className="flex items-center gap-2">
                      <Globe className="h-4 w-4" />
                      <span>Public</span>
                    </div>
                  </SelectItem>
                  <SelectItem value="private">
                    <div className="flex items-center gap-2">
                      <Lock className="h-4 w-4" />
                      <span>Private</span>
                    </div>
                  </SelectItem>
                </SelectContent>
              </Select>
            </div>

            <div className="flex gap-2">
              <Button
                className="flex-1"
                onClick={handleCancelVisibility}
                variant="outline"
              >
                Cancel
              </Button>
              <Button className="flex-1" onClick={handleSaveVisibility}>
                Save
              </Button>
            </div>
          </div>
        </PopoverContent>
      </Popover>
    );
  }

  return (
    <Popover>
      <PopoverTrigger asChild>
        <Button variant="outline">Publish</Button>
      </PopoverTrigger>
      <PopoverContent className="w-96 p-0">
        <div className="space-y-4 p-4">
          <div>
            <h3 className="mb-2 font-semibold">Publish to the Web</h3>
            <p className="text-muted-foreground text-sm">
              Publish this project to the web using Vercel. After you publish
              your app, you will get a URL to your app.
            </p>
          </div>

          <div className="space-y-2">
            <Button
              className="w-full justify-between shadow-none"
              onClick={() => setViewState("domain")}
              type="button"
              variant="secondary"
            >
              <div className="flex items-center gap-3">
                <Edit3 className="h-4 w-4 text-muted-foreground" />
                <span className="text-sm">Customize Domain</span>
              </div>
              <ChevronRight className="h-4 w-4 text-muted-foreground" />
            </Button>

            <Button
              className="w-full justify-between shadow-none"
              onClick={() => setViewState("visibility")}
              type="button"
              variant="secondary"
            >
              <div className="flex items-center gap-3">
                <Eye className="h-4 w-4 text-muted-foreground" />
                <span className="text-sm">Visibility</span>
              </div>
              <div className="flex items-center gap-2">
                <span className="text-muted-foreground text-sm capitalize">
                  {visibility}
                </span>
                <ChevronRight className="h-4 w-4 text-muted-foreground" />
              </div>
            </Button>
          </div>

          {state.status === "ready" ? (
            <div className="space-y-3">
              <Button
                className="w-full"
                onClick={() =>
                  window.open(
                    `https://${state.url}`,
                    "_blank",
                    "noopener,noreferrer"
                  )
                }
              >
                View your deployment
                <ExternalLink className="h-4 w-4" />
              </Button>
            </div>
          ) : (
            <Button
              className="w-full"
              disabled={
                state.status === "deploying" || state.status === "polling"
              }
              onClick={handleDeploy}
            >
              {state.status === "deploying" || state.status === "polling"
                ? state.progress
                : "Publish to Production"}
            </Button>
          )}
        </div>
      </PopoverContent>
    </Popover>
  );
}
